fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    // Precompute popcount-depth for numbers up to 1e15, but since it's not feasible,
    // we'll compute it on the fly with memoization.
    use std::collections::HashMap;

    // Memoization for popcount-depth
    let mut memo_depth = HashMap::new();

    // Function to compute popcount (number of 1 bits)
    fn popcount(mut x: i64) -> i64 {
        let mut count = 0;
        while x > 0 {
            count += x & 1;
            x >>= 1;
        }
        count
    }

    // Function to compute popcount-depth with memoization
    fn compute_depth(x: i64, memo: &mut HashMap<i64, i64>) -> i64 {
        if x == 1 {
            return 0;
        }
        if let Some(&depth) = memo.get(&x) {
            return depth;
        }
        let next = popcount(x);
        let depth = 1 + compute_depth(next, memo);
        memo.insert(x, depth);
        depth
    }

    // Process the nums array to get initial depths
    let mut nums = nums;
    let mut depths: Vec<i64> = nums.iter().map(|&x| compute_depth(x, &mut memo_depth)).collect();

    let mut answer = Vec::new();

    for query in queries {
        if query[0] == 1 {
            let l = query[1] as usize;
            let r = query[2] as usize;
            let k = query[3];
            let count = depths[l..=r].iter().filter(|&&d| d == k).count() as i64;
            answer.push(count);
        } else if query[0] == 2 {
            let idx = query[1] as usize;
            let val = query[2];
            nums[idx] = val;
            depths[idx] = compute_depth(val, &mut memo_depth);
        }
    }

    answer
}
