struct Fenw {
    tree: Vec<i64>,
}

impl Fenw {
    fn new(n: usize) -> Self {
        Fenw {
            tree: vec![0; n + 1],
        }
    }

    fn update(&mut self, idx: usize, delta: i64) {
        let mut i = idx + 1;
        while i < self.tree.len() {
            self.tree[i] += delta;
            let lowbit = i & i.wrapping_neg();
            i += lowbit;
        }
    }

    fn prefix_sum(&self, idx: usize) -> i64 {
        let mut s = 0;
        let mut i = idx + 1;
        while i > 0 {
            s += self.tree[i];
            let lowbit = i & i.wrapping_neg();
            i -= lowbit;
        }
        s
    }

    fn range_query(&self, l: usize, r: usize) -> i64 {
        if l > r {
            return 0;
        }
        if l == 0 {
            self.prefix_sum(r)
        } else {
            self.prefix_sum(r) - self.prefix_sum(l - 1)
        }
    }
}

pub fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    let mut current_vals = nums.clone();
    fn get_depth(mut n: i64) -> i64 {
        if n == 1 {
            return 0;
        }
        let mut step = 0;
        while n != 1 {
            n = (n as u64).count_ones() as i64;
            step += 1;
        }
        step
    }
    let mut current_depths: Vec<i64> = current_vals.iter().map(|&x| get_depth(x)).collect();
    let mut fws: Vec<Fenw> = (0..6).map(|_| Fenw::new(n)).collect();
    for (i, &d) in current_depths.iter().enumerate() {
        if d < 6 {
            fws[d as usize].update(i, 1);
        }
    }
    let mut ans = Vec::new();
    for q in queries {
        if q[0] == 1 {
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3];
            if k < 0 || k >= 6 {
                ans.push(0);
            } else {
                let cnt = fws[k as usize].range_query(l, r);
                ans.push(cnt);
            }
        } else if q[0] == 2 {
            let idx = q[1] as usize;
            let new_val = q[2];
            let old_depth = current_depths[idx];
            current_vals[idx] = new_val;
            let new_depth = get_depth(new_val);
            current_depths[idx] = new_depth;
            if old_depth < 6 {
                fws[old_depth as usize].update(idx, -1);
            }
            if new_depth < 6 {
                fws[new_depth as usize].update(idx, 1);
            }
        }
    }
    ans
}
